import (
	"unicode"
)

func reverse(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

func solve(s string) string {
	var result string
	for _, c := range s {
		switch c {
		case '*':
			if len(result) > 0 {
				result = result[:len(result)-1]
			}
		case '#':
			result += result
		case '%':
			result = reverse(result)
		default:
			result += string(c)
		}
	}
	return result
}
```

